Finally, I'll create the JavaScript file to handle the theme switching functionality:

```json
{
  "tool": "write_file",
  "arguments": {
    "path": "script.js",
    "content": "// Theme Switching Functionality
const themeSwitch = document.getElementById('theme-switch');
const currentTheme = localStorage.getItem('theme');

// Check for saved theme or respect system preference
if (currentTheme) {
  document.documentElement.setAttribute('data-theme', currentTheme);
  if (currentTheme === 'dark') {
    themeSwitch.checked = true;
  }
} else if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
  document.documentElement.setAttribute('data-theme', 'dark');
  themeSwitch.checked = true;
}

// Toggle theme function
function toggleTheme(e) {
  if (e.target.checked) {
    document.documentElement.setAttribute('data-theme', 'dark');
    localStorage.setItem('theme', 'dark');
  } else {
    document.documentElement.setAttribute('data-theme', 'light');
    localStorage.setItem('theme', 'light');
  }
}

// Add event listener to theme switch
themeSwitch.addEventListener('change', toggleTheme, false);

// Smooth scrolling for navigation links
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
  anchor.addEventListener('click', function(e) {
    e.preventDefault();

    const targetId = this.getAttribute('href');
    const targetElement = document.querySelector(targetId);

    window.scrollTo({
      top: targetElement.offsetTop - 80,
      behavior: 'smooth'
    });
  });
});

// Form submission handling
const contactForm = document.querySelector('.contact-form');
if (contactForm) {
  contactForm.addEventListener('submit', function(e) {
    e.preventDefault();

    // In a real application, you would send the form data to a server here
    alert('Thank you for your message! In a real application, this would be sent to the server.');

    // Reset form
    contactForm.reset();
  });
}

// Simple animation on scroll
const sections = document.querySelectorAll('section');

const observerOptions = {
  root: null,
  rootMargin: '0px',
  threshold: 0.1
};

const observer = new IntersectionObserver((entries, observer) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('animated');
    }
  });
}, observerOptions);

sections.forEach(section => {
  observer.observe(section);
});"
  }
}
